    public void BeginWriteTransaction()
    {
        if (_activeTransaction != null || ClientContext.ActiveTransaction != null)
            throw new InvalidOperationException("Transaction already active.");

        EnsureDatabaseWritable();
        StartTransaction(BogDb.Core.Transaction.TransactionType.WRITE);
        _activeTransaction = ClientContext.ActiveTransaction;
    }

    public void Commit()
    {
        var transaction = _activeTransaction ?? ClientContext.ActiveTransaction;
        if (transaction == null)
            throw new InvalidOperationException("No active transaction.");

        ClientContext.Commit();
        _database.PersistState();
        
        // In a full implementation, we flush WAL and update Catalog isolation version
        _database.Catalog.IncrementVersion();
        _database.MetricsRegistry.RecordCommit();

        _activeTransaction = null;
    }

    public void Rollback()
    {
        var transaction = _activeTransaction ?? ClientContext.ActiveTransaction;
        if (transaction == null)
            throw new InvalidOperationException("No active transaction.");

        ClientContext.Rollback();
        if (transaction.IsWriteTransaction())
            _database.DiscardPendingRecoveryArtifacts(transaction);

        _database.MetricsRegistry.RecordRollback();
        _activeTransaction = null;
    }

    /// <summary>
    /// Executes a block of direct-write operations inside a single write transaction.
    /// If the caller already has an active write transaction, the work is folded into it.
    /// Otherwise, this method owns the transaction lifetime and performs a single persist.
    /// </summary>
    public void ExecuteWriteTransaction(Action action)
    {
        ArgumentNullException.ThrowIfNull(action);

        var startedLocalTransaction = false;
        try
        {
            if (ClientContext.ActiveTransaction == null)
            {
                EnsureDatabaseWritable();
                StartTransaction(BogDb.Core.Transaction.TransactionType.WRITE);
                _activeTransaction = ClientContext.ActiveTransaction;
                startedLocalTransaction = true;
            }

            action();

            if (startedLocalTransaction)
            {
                ClientContext.Commit();
                _database.PersistState();
                _database.Catalog.IncrementVersion();
                _database.MetricsRegistry.RecordCommit();
                _activeTransaction = null;
            }
        }
        catch
        {
            if (startedLocalTransaction && ClientContext.ActiveTransaction != null)
            {
                var rollbackTx = ClientContext.ActiveTransaction;
                ClientContext.Rollback();
                if (rollbackTx != null && rollbackTx.IsWriteTransaction())
                    _database.DiscardPendingRecoveryArtifacts(rollbackTx);
                _database.MetricsRegistry.RecordRollback();
                _activeTransaction = null;
            }

            throw;
        }
    }

    /// <summary>
    /// Commits the active transaction for schema-only changes.
    /// Even without graph data mutations, the schema surface must be durable
    /// across crash/reopen boundaries, so we persist the catalog + empty table snapshot.
    /// </summary>
    public void CommitSchemaOnly()
    {
        var transaction = _activeTransaction ?? ClientContext.ActiveTransaction;
        if (transaction == null)
            throw new InvalidOperationException("No active transaction.");

        ClientContext.Commit();
        _database.PersistState();
        _database.Catalog.IncrementVersion();
        _database.MetricsRegistry.RecordCommit();

        _activeTransaction = null;
    }

