    public BogDbPreparedStatement Prepare(string query)
    {
        try
        {
            var preparedMetadata = DescribePreparedStatement(query);
            return new BogDbPreparedStatement(
                this,
                query,
                isSuccess: true,
                errorMessage: string.Empty,
                parameterNames: ExtractParameterNames(query),
                resultColumns: preparedMetadata.ResultColumns,
                parameterExpectedTypes: preparedMetadata.ParameterExpectedTypes);
        }
        catch (Exception ex)
        {
            return new BogDbPreparedStatement(
                this,
                query,
                isSuccess: false,
                errorMessage: ex.Message,
                parameterNames: ExtractParameterNames(query));
        }
    }

    public TimeSpan QueryTimeout
    {
        get => ClientContext.TimeoutInMs == 0
            ? Timeout.InfiniteTimeSpan
            : TimeSpan.FromMilliseconds(ClientContext.TimeoutInMs);
        set
        {
            if (value < Timeout.InfiniteTimeSpan)
                throw new ArgumentOutOfRangeException(nameof(value));

            ClientContext.TimeoutInMs = value == Timeout.InfiniteTimeSpan
                ? 0
                : checked((ulong)Math.Ceiling(value.TotalMilliseconds));
        }
    }

    public void SetQueryTimeout(TimeSpan timeout) => QueryTimeout = timeout;

    public void SetQueryTimeout(long milliseconds)
    {
        if (milliseconds < Timeout.Infinite)
            throw new ArgumentOutOfRangeException(nameof(milliseconds));

        QueryTimeout = milliseconds == Timeout.Infinite
            ? Timeout.InfiniteTimeSpan
            : TimeSpan.FromMilliseconds(milliseconds);
    }

