    public QueryResult.QueryResult Query(
        string query,
        IReadOnlyDictionary<string, object?>? parameters,
        BogDbQueryMetricsOptions? metricsOptions)
    {
        var startedAt = Stopwatch.StartNew();
        var queryMetrics = new QueryMetricsContext(metricsOptions);
        queryMetrics.Start();
        ClientContext.CurrentQueryMetrics = queryMetrics;

        // ── Context for table functions and GDS scalar functions ─────────────────
        // P1-053: wire DB catalog into scalar table-function stubs.
        Function.Table.TableFunctions.SetCatalogContext(_database);
        // Wire DB into GDS scalar functions (node_degree, has_path, graph_density, k_hop_count).
        Function.Gds.GdsFunctions.SetDatabaseContext(_database);

        var trimmed = query.Trim();

        // ── COMMIT / ROLLBACK without BEGIN ─────────────────────────────────────
        if (_activeTransaction == null && ClientContext.ActiveTransaction == null)
        {
            var upper = trimmed.ToUpperInvariant();
            if (upper == "COMMIT")
                return FinalizeQueryResult(
                    QueryResult.QueryResult.FromError("Cannot COMMIT: no active transaction."),
                    queryMetrics,
                    success: false);
            if (upper == "ROLLBACK")
                return FinalizeQueryResult(
                    QueryResult.QueryResult.FromError("Cannot ROLLBACK: no active transaction."),
                    queryMetrics,
                    success: false);
        }

        // ── Window function intercept ────────────────────────────────────────────
        if (Processor.Operator.Window.WindowFunctionService.IsWindowQuery(trimmed))
            return FinalizeQueryResult(
                Processor.Operator.Window.WindowFunctionService.Execute(this, trimmed),
                queryMetrics,
                success: true);

        // ── GDS CALL intercept ───────────────────────────────────────────────────
        var gdsResult = TryExecuteGdsCall(trimmed);
        if (gdsResult != null)
            return FinalizeQueryResult(gdsResult, queryMetrics, success: gdsResult.IsSuccess);

        var startedLocalTransaction = false;
        try
        {
            ThrowIfInterruptedOrTimedOut(startedAt);

            query = NormalizePlannerLoadFromLiteralPath(query);

            // 0.5. Pre-process CALL { subquery } blocks before ANTLR parsing
            var callSubqueryPreprocessor = new Parser.Antlr4.CallSubqueryPreprocessor();
            query = callSubqueryPreprocessor.Preprocess(query);

            // 1. Parse
            var inputStream = new Antlr4.Runtime.AntlrInputStream(query);
            var lexer = new CypherLexer(inputStream);
            var syntaxErrors = new List<string>();
            lexer.RemoveErrorListeners();
            lexer.AddErrorListener(new QueryLexerSyntaxErrorListener(syntaxErrors));
            var tokenStream = new Antlr4.Runtime.CommonTokenStream(lexer);
            var parser = new CypherParser(tokenStream);
            parser.RemoveErrorListeners();
            parser.AddErrorListener(new QuerySyntaxErrorListener(syntaxErrors));
            var root = parser.ku_Statements();
            ThrowIfInterruptedOrTimedOut(startedAt);
            if (syntaxErrors.Count > 0)
            {
                return QueryResult.QueryResult.FromError(string.Join(Environment.NewLine, syntaxErrors));
            }
            var transformer = new Parser.Antlr4.Transformer(root, callSubqueryPreprocessor.ExtractedBodies);
            var statements = transformer.Transform();
            ThrowIfInterruptedOrTimedOut(startedAt);

            if (statements.Count == 0)
                return QueryResult.QueryResult.FromError("No statement was parsed from the provided query.");

            // For Phase 7 testing, we assume single-statement queries.
            var statement = statements[0];

            // Transaction control statements are handled directly at connection level.
            if (statement.GetStatementType() == StatementType.TRANSACTION)
            {
                return ExecuteTransactionStatement((TransactionStatement)statement);
            }

            if (ClientContext.ActiveTransaction == null)
            {
                StartTransaction(
                    RequiresWriteTransaction(statement)
                        ? BogDb.Core.Transaction.TransactionType.WRITE
                        : BogDb.Core.Transaction.TransactionType.READ_ONLY);
                startedLocalTransaction = true;
            }

            // 2. Bind
            var binder = new BogDb.Core.Binder.Binder(
                _database.Catalog,
                ReadCopyCsvHeader,
                name => _database.TryGetExtensionOption(name, out var option) ? option : null);
            var boundStatement = binder.Bind(statement);
            ThrowIfInterruptedOrTimedOut(startedAt);

            if (TryExecuteDdlStatement(statement, boundStatement, out var ddlResult))
            {
                if (startedLocalTransaction)
                {
                    ClientContext.Commit();
                    _database.PersistState();
                    startedLocalTransaction = false;
                }

                return ddlResult;
            }

            // 3. Plan
            var planner = new BogDb.Core.Planner.Planner(_database);
            var logicalPlan = planner.GetBestPlan(boundStatement);
            ThrowIfInterruptedOrTimedOut(startedAt);

            // 4. Optimize
            var optimizer = new Optimizer.Optimizer(_database);
            optimizer.Optimize(logicalPlan);
            ThrowIfInterruptedOrTimedOut(startedAt);

            // 5. Execute 
            var planMapper = new PlanMapper(_database);
            var physicalPlan = planMapper.MapLogicalPlanToPhysical(logicalPlan);
            ThrowIfInterruptedOrTimedOut(startedAt);

            if (boundStatement is BoundExplain explain)
            {
                var explainText = explain.ExplainType == ExplainType.LOGICAL_PLAN
                    ? PlanPrinter.Print(logicalPlan)
                    : PhysicalPlanPrinter.Print(physicalPlan);
                var explainResult = QueryResult.QueryResult.FromOrderedRows(
                    new[]
                    {
                        new Dictionary<string, object?>
                        {
                            ["explain result"] = explainText
                        }
                    },
                    new[] { "explain result" });

                if (startedLocalTransaction)
                {
                    ClientContext.Commit();
                    _database.PersistState();
                    startedLocalTransaction = false;
                }

                return FinalizeQueryResult(explainResult, queryMetrics, success: true);
            }
        
            var execContext = new BogDb.Core.Processor.ExecutionContext(ClientContext.ActiveTransaction, _database.BufferManager, _database)
            {
                ParameterBindings = NormalizeParameterBindings(parameters),
                QueryMetrics = queryMetrics
            };
        
            // 6. Aggregate
            // Extract RETURN-clause column names so QueryResult can expose them via GetAsDictionary().
            var columnNames = System.Array.Empty<string>();
            var columnTypes = System.Array.Empty<LogicalTypeID>();
            if (boundStatement is BogDb.Core.Binder.BoundRegularQuery rq
                && rq.GetSingleQuery(0).HasReturnClause())
            {
                var items = rq.GetSingleQuery(0).ReturnClause!.Items;
                columnNames = items.Select(it => it.ColumnName).ToArray();
                columnTypes = items.Select(it => it.Expression.DataType).ToArray();
            }

            var resultCollector = new BogDb.Core.Processor.Operator.Result.ResultCollector(physicalPlan.LastOperator, 999, columnNames);
            resultCollector.GetNextTuple(execContext);
            ThrowIfInterruptedOrTimedOut(startedAt);

            if (startedLocalTransaction)
            {
                ClientContext.Commit();
                _database.PersistState();
                startedLocalTransaction = false;
            }

            return FinalizeQueryResult(new QueryResult.QueryResult(resultCollector, columnTypes), queryMetrics, success: true);
        }
        catch (Exception ex)
        {
            if (startedLocalTransaction)
            {
                var rollbackTx = ClientContext.ActiveTransaction;
                try
                {
                    ClientContext.Rollback();
                    if (rollbackTx != null && rollbackTx.IsWriteTransaction())
                        _database.DiscardPendingRecoveryArtifacts(rollbackTx);
                }
                catch
                {
                    // Preserve the original query error in returned QueryResult.
                }
            }
            return FinalizeQueryResult(QueryResult.QueryResult.FromError(ex.Message), queryMetrics, success: false);
        }
        finally
        {
            ClientContext.CurrentQueryMetrics = null;
        }
    }

