    private QueryResult.QueryResult ExecuteTransactionStatement(TransactionStatement statement)
    {
        try
        {
            switch (statement.Command)
            {
                case TransactionCommand.BEGIN:
                    if (ClientContext.ActiveTransaction != null)
                        throw new InvalidOperationException("Transaction already active.");
                    StartTransaction(statement.IsReadOnly
                        ? BogDb.Core.Transaction.TransactionType.READ_ONLY
                        : BogDb.Core.Transaction.TransactionType.WRITE);
                    break;
                case TransactionCommand.COMMIT:
                    ClientContext.Commit();
                    _database.PersistState();
                    _database.MetricsRegistry.RecordCommit();
                    break;
                case TransactionCommand.ROLLBACK:
                    var rollbackTx = ClientContext.ActiveTransaction;
                    ClientContext.Rollback();
                    if (rollbackTx != null && rollbackTx.IsWriteTransaction())
                        _database.DiscardPendingRecoveryArtifacts(rollbackTx);
                    _database.MetricsRegistry.RecordRollback();
                    break;
                case TransactionCommand.CHECKPOINT:
                    _database.PersistState();
                    break;
                default:
                    throw new NotSupportedException($"Unsupported transaction command: {statement.Command}");
            }

            var noOp = new BogDb.Core.Processor.Operator.NoOpPhysicalOperator(0);
            var collector = new BogDb.Core.Processor.Operator.Result.ResultCollector(noOp, 999);
            var execContext = new BogDb.Core.Processor.ExecutionContext(
                BogDb.Core.Transaction.Transaction.DUMMY_TRANSACTION, _database.BufferManager);
            collector.GetNextTuple(execContext);
            return new QueryResult.QueryResult(collector);
        }
        catch (Exception ex)
        {
            return QueryResult.QueryResult.FromError(ex.Message);
        }
    }

