    private static bool RequiresWriteTransaction(Statement statement)
    {
        switch (statement.GetStatementType())
        {
            case StatementType.CREATE_TABLE:
            case StatementType.DROP:
            case StatementType.ALTER:
            case StatementType.CREATE_MACRO:
            case StatementType.ATTACH_DATABASE:
            case StatementType.DETACH_DATABASE:
            case StatementType.USE_DATABASE:
            case StatementType.EXTENSION:
                return true;
        }

        if (statement is not RegularQuery regularQuery)
            return false;

        for (var i = 0; i < regularQuery.GetNumSingleQueries(); i++)
        {
            if (regularQuery.GetSingleQuery(i).GetNumUpdatingClauses() > 0)
                return true;
        }

        return false;
    }

    private bool TryExecuteDdlStatement(Statement statement, BoundStatement boundStatement, out QueryResult.QueryResult result)
    {
        switch (statement)
        {
            case CreateNodeTable createNode when boundStatement is BoundCreateNodeTable boundCreateNode:
            {
                EnsureNodeTableWithDefinitions(createNode.TableName, ToPropertyDefinitions(boundCreateNode.Info.Properties));
                result = CreateNoOpSuccessResult();
                return true;
            }
            case CreateRelTable createRel when boundStatement is BoundCreateRelTable boundCreateRel:
            {
                EnsureRelTableWithDefinitions(
                    createRel.TableName,
                    createRel.SrcTableName,
                    createRel.DstTableName,
                    ToPropertyDefinitions(boundCreateRel.Info.Properties));
                result = CreateNoOpSuccessResult();
                return true;
            }
            case DropTable dropTable when boundStatement is BoundDropTable:
            {
                _database.DropTable(GetRequiredWriteTransaction(), dropTable.TableName);
                result = CreateNoOpSuccessResult();
                return true;
            }
            case AlterTableAddProperty alterAddProperty:
            {
                var defaultValue = GetLiteralDefaultValue(alterAddProperty.DefaultExpression, out var defaultExpressionName);

                _database.AlterTableAddProperty(
                    GetRequiredWriteTransaction(),
                    alterAddProperty.TableName,
                    alterAddProperty.PropertyName,
                    ParseLogicalType(alterAddProperty.TypeName),
                    alterAddProperty.TypeName,
                    defaultValue,
                    defaultExpressionName);
                result = CreateNoOpSuccessResult();
                return true;
            }
            case AlterTableDropProperty alterDropProperty:
            {
                _database.AlterTableDropProperty(
                    GetRequiredWriteTransaction(),
                    alterDropProperty.TableName,
                    alterDropProperty.PropertyName);
                result = CreateNoOpSuccessResult();
                return true;
            }
            case AlterTableRenameTable alterRenameTable:
            {
                _database.AlterTableRename(
                    GetRequiredWriteTransaction(),
                    alterRenameTable.TableName,
                    alterRenameTable.NewTableName);
                result = CreateNoOpSuccessResult();
                return true;
            }
            case AlterTableRenameProperty alterRenameProperty:
            {
                _database.AlterTableRenameProperty(
                    GetRequiredWriteTransaction(),
                    alterRenameProperty.TableName,
                    alterRenameProperty.OldPropertyName,
                    alterRenameProperty.NewPropertyName);
                result = CreateNoOpSuccessResult();
                return true;
            }
            case AlterTableConnectionChange alterConnectionChange:
            {
                _database.AlterTableConnectionChange(
                    GetRequiredWriteTransaction(),
                    alterConnectionChange.TableName,
                    alterConnectionChange.IsAdd,
                    alterConnectionChange.IgnoreIfPresentOrMissing,
                    alterConnectionChange.FromTableName,
                    alterConnectionChange.ToTableName);
                result = CreateNoOpSuccessResult();
                return true;
            }
            case AttachDatabaseStatement when boundStatement is BoundAttachDatabase boundAttach:
            {
                var dbType = boundAttach.DbType.ToUpperInvariant();
                if (!_database.TryResolveStorageExtension(dbType, out var storageExtension))
                {
                    var errMsg = $"No loaded extension can handle database type: {dbType}.";
                    if (string.Equals(dbType, "DUCKDB", StringComparison.OrdinalIgnoreCase))
                        errMsg += "\nDid you forget to load duckdb extension?\nYou can load it by: LOAD EXTENSION duckdb;";
                    else if (string.Equals(dbType, "POSTGRES", StringComparison.OrdinalIgnoreCase))
                        errMsg += "\nDid you forget to load postgres extension?\nYou can load it by: LOAD EXTENSION postgres;";
                    throw new InvalidOperationException(errMsg);
                }
                var attachedDb = storageExtension.Attach(_database, boundAttach.Alias, boundAttach.Path, boundAttach.Options);
                _database.AddAttachedDatabase(attachedDb);
                result = CreateMessageResult("Attached database successfully.");
                return true;
            }
            case DetachDatabaseStatement when boundStatement is BoundDetachDatabase boundDetach:
            {
                if (!_database.RemoveAttachedDatabase(boundDetach.DbName))
                    throw new InvalidOperationException($"Database '{boundDetach.DbName}' is not attached.");
                // Clear default database reference if detaching the current default
                if (string.Equals(DefaultDatabaseAlias, boundDetach.DbName, StringComparison.OrdinalIgnoreCase))
                    DefaultDatabaseAlias = null;
                result = CreateMessageResult("Detached database successfully.");
                return true;
            }
            case UseDatabaseStatement when boundStatement is BoundUseDatabase boundUse:
            {
                if (!_database.TryGetAttachedDatabase(boundUse.DbName, out _))
                    throw new InvalidOperationException($"Database '{boundUse.DbName}' is not attached.");
                DefaultDatabaseAlias = boundUse.DbName;
                result = CreateMessageResult("Used database successfully.");
                return true;
            }
            default:
                result = null!;
                return false;
        }
    }

    private static IReadOnlyDictionary<string, object?>? NormalizeParameterBindings(
        IReadOnlyDictionary<string, object?>? parameters)
    {
        if (parameters == null || parameters.Count == 0)
            return null;

        var normalized = new Dictionary<string, object?>(parameters.Count, StringComparer.OrdinalIgnoreCase);
        foreach (var (key, value) in parameters)
        {
            if (string.IsNullOrWhiteSpace(key))
                throw new InvalidOperationException("Parameter names cannot be empty.");

            var normalizedKey = key[0] == '$' ? key[1..] : key;
            if (string.IsNullOrWhiteSpace(normalizedKey))
                throw new InvalidOperationException("Parameter names cannot be empty.");

            normalized[normalizedKey] = value;
        }

        return normalized;
    }

    private PreparedStatementMetadata DescribePreparedStatement(string query)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(query);

        var normalizedQuery = NormalizePlannerLoadFromLiteralPath(query);
        var preprocCallSub = new Parser.Antlr4.CallSubqueryPreprocessor();
        normalizedQuery = preprocCallSub.Preprocess(normalizedQuery);
        var inputStream = new AntlrInputStream(normalizedQuery);
        var lexer = new CypherLexer(inputStream);
        var syntaxErrors = new List<string>();
        lexer.RemoveErrorListeners();
        lexer.AddErrorListener(new QueryLexerSyntaxErrorListener(syntaxErrors));
        var tokenStream = new CommonTokenStream(lexer);
        var parser = new CypherParser(tokenStream);
        parser.RemoveErrorListeners();
        parser.AddErrorListener(new QuerySyntaxErrorListener(syntaxErrors));
        var root = parser.ku_Statements();
        if (syntaxErrors.Count > 0)
            throw new InvalidOperationException(string.Join(Environment.NewLine, syntaxErrors));

        var transformer = new Parser.Antlr4.Transformer(root, preprocCallSub.ExtractedBodies);
        var statements = transformer.Transform();
        if (statements.Count == 0)
            throw new InvalidOperationException("No statement was parsed from the provided query.");
        if (statements.Count > 1)
            throw new InvalidOperationException("Prepared statements currently support a single statement only.");

        var statement = statements[0];
        if (statement.GetStatementType() == StatementType.TRANSACTION)
            throw new InvalidOperationException("Transaction statements cannot be prepared.");

        var binder = new BogDb.Core.Binder.Binder(
            _database.Catalog,
            ReadCopyCsvHeader,
            name => _database.TryGetExtensionOption(name, out var option) ? option : null);
        var boundStatement = binder.Bind(statement);
        return BuildPreparedStatementMetadata(boundStatement, binder.ParameterExpectedTypes);
    }

    private static PreparedStatementMetadata BuildPreparedStatementMetadata(
        BoundStatement boundStatement,
        IReadOnlyDictionary<string, LogicalTypeID> parameterExpectedTypes)
    {
        var preparedParameterTypes = parameterExpectedTypes.ToDictionary(
            pair => pair.Key,
            pair => BogDbLogicalType.FromId(pair.Value),
            StringComparer.OrdinalIgnoreCase);

        if (boundStatement is BoundRegularQuery regularQuery &&
            regularQuery.GetNumSingleQueries() > 0 &&
            regularQuery.GetSingleQuery(0).HasReturnClause())
        {
            var resultColumns = regularQuery
                .GetSingleQuery(0)
                .ReturnClause!
                .Items
                .Select((item, ordinal) => new BogDbColumnDescriptor(
                    item.ColumnName,
                    ordinal,
                    BogDbLogicalType.FromId(item.Expression.DataType)))
                .ToArray();
            return new PreparedStatementMetadata(resultColumns, preparedParameterTypes);
        }

        return new PreparedStatementMetadata(Array.Empty<BogDbColumnDescriptor>(), preparedParameterTypes);
    }

    private void ThrowIfInterruptedOrTimedOut(Stopwatch stopwatch)
    {
        if (Interlocked.Exchange(ref _interruptRequested, 0) == 1)
            throw new OperationCanceledException("Query execution was interrupted.");

        var timeoutMs = ClientContext.TimeoutInMs;
        if (timeoutMs > 0 && stopwatch.ElapsedMilliseconds > (long)timeoutMs)
            throw new TimeoutException($"Query execution exceeded the configured timeout of {timeoutMs} ms.");
    }

    private static IReadOnlyList<string> ExtractParameterNames(string query)
    {
        if (string.IsNullOrWhiteSpace(query))
            return Array.Empty<string>();

        var matches = System.Text.RegularExpressions.Regex.Matches(
            query,
            @"(?<![A-Za-z0-9_])\$(?<name>[A-Za-z_][A-Za-z0-9_]*)");

        if (matches.Count == 0)
            return Array.Empty<string>();

        var ordered = new List<string>(matches.Count);
        var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
        foreach (System.Text.RegularExpressions.Match match in matches)
        {
            var parameterName = match.Groups["name"].Value;
            if (seen.Add(parameterName))
                ordered.Add(parameterName);
        }

        return ordered;
    }

    private static List<PropertyDefinition> ToPropertyDefinitions(IReadOnlyList<BoundColumnDefinition> properties)
    {
        var result = new List<PropertyDefinition>(properties.Count);
        foreach (var property in properties)
        {
            result.Add(new PropertyDefinition(
                new ColumnDefinition(property.Name, property.Type, property.DeclaredType)));
        }

        return result;
    }

    private static LogicalTypeID ParseLogicalType(string typeName)
        => DeclaredTypeDescriptor.Parse(typeName).RuntimeType;

    private static object? GetLiteralDefaultValue(ParsedExpression? defaultExpression, out string defaultExpressionName)
    {
        defaultExpressionName = string.Empty;
        if (defaultExpression == null)
            return null;
        if (defaultExpression is not ParsedLiteralExpression literal)
            throw new InvalidOperationException("ALTER TABLE ... ADD ... DEFAULT currently supports literal defaults only.");

        defaultExpressionName = literal.GetRawName();
        return literal.Value;
    }

    private QueryResult.QueryResult CreateNoOpSuccessResult()
    {
        var noOp = new BogDb.Core.Processor.Operator.NoOpPhysicalOperator(0);
        var collector = new BogDb.Core.Processor.Operator.Result.ResultCollector(noOp, 999);
        var execContext = new BogDb.Core.Processor.ExecutionContext(
            BogDb.Core.Transaction.Transaction.DUMMY_TRANSACTION, _database.BufferManager);
        collector.GetNextTuple(execContext);
        return new QueryResult.QueryResult(collector);
    }

    private QueryResult.QueryResult FinalizeQueryResult(
        QueryResult.QueryResult result,
        QueryMetricsContext queryMetrics,
        bool success)
    {
        var totalMilliseconds = queryMetrics.Stop();
        var executionMetrics = queryMetrics.BuildExecutionMetrics(result.GetNumTuples());
        result.AttachTotalMilliseconds(totalMilliseconds);
        result.AttachExecutionMetrics(executionMetrics);
        _database.MetricsRegistry.RecordQuery(success && result.IsSuccess, totalMilliseconds, executionMetrics);
        return result;
    }

    private QueryResult.QueryResult CreateMessageResult(string message)
    {
        return QueryResult.QueryResult.FromOrderedRows(
            new[]
            {
                new Dictionary<string, object?>
                {
                    ["result"] = message
                }
            },
            new[] { "result" });
    }

    // ── GDS CALL helper ──────────────────────────────────────────────────────────

    private static readonly System.Text.RegularExpressions.Regex _gdsCallRegex =
        new System.Text.RegularExpressions.Regex(
            @"^CALL\s+(?<name>[A-Za-z_][A-Za-z0-9_]*)\s*\((?<args>[^)]*)\)\s*(?:YIELD|RETURN)\s+\*\s*;?$",
            System.Text.RegularExpressions.RegexOptions.IgnoreCase |
            System.Text.RegularExpressions.RegexOptions.Compiled);

    /// <summary>
    /// Intercepts <c>CALL algorithmName([args]) YIELD *</c> / <c>RETURN *</c>
    /// for registered GDS algorithms, runs the algorithm, and returns results
    /// as a <see cref="QueryResult.QueryResult"/>.
    /// Falls through to the Cypher parser for non-GDS CALL statements.
    /// </summary>
    private QueryResult.QueryResult? TryExecuteGdsCall(string query)
    {
        var match = _gdsCallRegex.Match(query);
        if (!match.Success) return null;

        var algoName = match.Groups["name"].Value;
        if (!GdsRegistry.IsGdsFunction(algoName)) return null;

        // Parse simple positional/keyword args from the argument string
        var argsRaw = match.Groups["args"].Value.Trim();
        var opts    = ParseGdsCallOptions(argsRaw);

        try
        {
            var op   = new PhysicalGdsCall(_database, algoName, opts, GetCurrentTransactionOrNull());
            var cols = op.OutputColumns;
            var rows = new List<Dictionary<string, object?>>();
            while (op.Next(out var row)) rows.Add(row);
            return QueryResult.QueryResult.FromTableFunctionRows(rows);
        }
        catch (Exception ex)
        {
            return QueryResult.QueryResult.FromError(ex.Message);
        }
    }

    /// <summary>
    /// Parses a CALL argument list into <see cref="GdsCallOptions"/>.
    /// Supports:
    ///   CALL algo('sourceId', maxIter, dampingFactor)    — positional
    ///   No args                                          — defaults
    /// </summary>
    private static GdsCallOptions ParseGdsCallOptions(string argsRaw)
    {
        if (string.IsNullOrWhiteSpace(argsRaw)) return GdsCallOptions.Defaults;

        // Split on commas (simple; does not handle nested parens)
        var parts = argsRaw.Split(',', StringSplitOptions.RemoveEmptyEntries);
        NodeId? sourceNode = null;
        int maxIter = 20;
        double damping = 0.85;
        string? weightProp = null;
        string direction = "OUT";

        for (int i = 0; i < parts.Length; i++)
        {
            var part = parts[i].Trim().Trim('\'', '"');
            switch (i)
            {
                case 0:
                    // First arg: source node id (string "offset" or "table:offset")
                    if (ulong.TryParse(part, out ulong off))
                        sourceNode = new NodeId(off);
                    else if (part.Contains(':'))
                    {
                        var seg = part.Split(':');
                        if (uint.TryParse(seg[0], out var tid) &&
                            ulong.TryParse(seg[1], out var o2))
                            sourceNode = new NodeId(o2, tid);
                    }
                    break;
                case 1:
                    if (int.TryParse(part, out var mi)) maxIter = mi;
                    break;
                case 2:
                    if (double.TryParse(part,
                        System.Globalization.NumberStyles.Float,
                        System.Globalization.CultureInfo.InvariantCulture, out var d))
                        damping = d;
                    break;
                case 3:
                    weightProp = string.IsNullOrWhiteSpace(part) ? null : part;
                    break;
                case 4:
                    direction = part.ToUpperInvariant() switch
                    {
                        "IN"   => "IN",
                        "BOTH" => "BOTH",
                        _      => "OUT",
                    };
                    break;
            }
        }

        return new GdsCallOptions
        {
            SourceNode     = sourceNode,
            MaxIterations  = maxIter,
            DampingFactor  = damping,
            WeightProperty = weightProp,
            Direction      = direction,
        };
    }

    // ── LOAD FROM helper ─────────────────────────────────────────────────────────
    private static readonly System.Text.RegularExpressions.Regex _loadFromRegex =
        new System.Text.RegularExpressions.Regex(
            @"^LOAD(?:\s+WITH\s+HEADERS\s*\(.*?\))?\s+FROM\s+[""'](?<path>.*?)[""']",
            System.Text.RegularExpressions.RegexOptions.IgnoreCase |
            System.Text.RegularExpressions.RegexOptions.Singleline);

    private static string NormalizePlannerLoadFromLiteralPath(string query)
    {
        var match = _loadFromRegex.Match(query.Trim());
        if (!match.Success)
            return query;

        var source = match.Groups["path"].Value;
        if (string.IsNullOrWhiteSpace(source) || !source.Contains('\\'))
            return query;

        var normalizedSource = source.Replace('\\', '/');
        return query.Replace(match.Groups["path"].Value, normalizedSource);
    }

    private static string ResolveFilePath(string path)
    {
        if (System.IO.File.Exists(path)) return path;

        // Strip leading ../ segments and search upward from binary dir
        var normalised = path.Replace('\\', System.IO.Path.DirectorySeparatorChar);
        var segments = normalised.Split(System.IO.Path.DirectorySeparatorChar, StringSplitOptions.RemoveEmptyEntries);
        var tail = string.Join(System.IO.Path.DirectorySeparatorChar.ToString(),
            segments.SkipWhile(s => s == ".."));

        var dir = new System.IO.DirectoryInfo(AppContext.BaseDirectory);
        while (dir != null)
        {
            var candidate = System.IO.Path.Combine(dir.FullName, tail);
            if (System.IO.File.Exists(candidate)) return candidate;
            dir = dir.Parent;
        }
        return path; // Let the function raise FileNotFoundException
    }

    private string ResolveReadablePath(string path)
        => IsRegisteredFileSystemPath(path) ? path : ResolveFilePath(path);

    private List<string> ReadCopyCsvHeader(string path)
        => Processor.Operator.Persistent.Reader.CSV.CsvFileAccess.ReadCsvHeader(_database, path);
