    /// <summary>
    /// Executes a sequential .cypher file script extracting statements delimited by semicolons natively.
    /// </summary>
    public void ExecuteScript(string filePath)
    {
        string content = ReadAllTextFromPath(filePath);
        var queries = content.Split(';', StringSplitOptions.RemoveEmptyEntries);
        foreach (var q in queries)
        {
            if (string.IsNullOrWhiteSpace(q)) continue;
            Query(q);
        }
    }

    /// <summary>
    /// Phase 33: LINQ Integration allowing native Queryable tracking across generic Entity configurations natively.
    /// </summary>
    public System.Linq.IQueryable<T> AsQueryable<T>(string label = "")
    {
        var provider = new BogDb.Core.Linq.BogDbQueryProvider(this, string.IsNullOrEmpty(label) ? typeof(T).Name : label);
        return new BogDb.Core.Linq.BogDbQueryable<T>(provider, System.Linq.Expressions.Expression.Constant(this));
    }

