    public void EnsureNodeTable(string tableName)
        => EnsureNodeTable(tableName, new Dictionary<string, LogicalTypeID>());

    public void EnsureNodeTable(string tableName, Dictionary<string, LogicalTypeID> properties)
    {
        var propertyDefinitions = new List<PropertyDefinition>(properties.Count);
        foreach (var prop in properties)
        {
            propertyDefinitions.Add(new PropertyDefinition(new ColumnDefinition(prop.Key, prop.Value)));
        }

        EnsureNodeTableWithDefinitions(tableName, propertyDefinitions);
    }

    private void EnsureNodeTableWithDefinitions(string tableName, IReadOnlyList<PropertyDefinition> properties)
    {
        var transaction = GetRequiredWriteTransaction();

        if (_database.Catalog.ContainsTable(transaction, tableName))
            return;

        var entry = new NodeTableCatalogEntry(tableName, 0); 
        foreach (var propDef in properties)
        {
            entry.AddProperty(propDef);
        }
        _database.Catalog.CreateTableEntry(transaction, entry);
        
        var table = new NodeTableData();
        _database.BindTablePersistenceSurface(tableName, table);
        _database.NodeTables[tableName] = table;
        
        _database.StorageManager.GetWAL().LogCreateTableRecord(checked((uint)entry.TableID), entry);
    }

    public void EnsureRelTable(string tableName, string fromTable, string toTable)
        => EnsureRelTable(tableName, fromTable, toTable, new Dictionary<string, LogicalTypeID>());

    public void EnsureRelTable(string tableName, string fromTable, string toTable, Dictionary<string, LogicalTypeID> properties)
    {
        var propertyDefinitions = new List<PropertyDefinition>(properties.Count);
        foreach (var prop in properties)
        {
            propertyDefinitions.Add(new PropertyDefinition(new ColumnDefinition(prop.Key, prop.Value)));
        }

        EnsureRelTableWithDefinitions(tableName, fromTable, toTable, propertyDefinitions);
    }

    private void EnsureRelTableWithDefinitions(string tableName, string fromTable, string toTable, IReadOnlyList<PropertyDefinition> properties)
    {
        var transaction = GetRequiredWriteTransaction();

        if (_database.Catalog.ContainsTable(transaction, tableName))
            return;

        var entry = new RelGroupCatalogEntry(tableName, fromTable, toTable); 
        foreach (var propDef in properties)
        {
            entry.AddProperty(propDef);
        }
        _database.Catalog.CreateTableEntry(transaction, entry);
        
        var table = new RelTableData(fromTable, toTable);
        _database.BindTablePersistenceSurface(tableName, table);
        _database.RelTables[tableName] = table;
        
        _database.StorageManager.GetWAL().LogCreateTableRecord(checked((uint)entry.TableID), entry);
    }

    public void UpsertNode(string tableName, object id, Dictionary<string, object> properties)
    {
        var transaction = GetRequiredWriteTransaction();

        if (!_database.NodeTables.TryGetValue(tableName, out var table))
        {
            table = new NodeTableData();
            _database.BindTablePersistenceSurface(tableName, table);
            _database.NodeTables[tableName] = table;
        }

        var normalized = NormalizeProperties(tableName, properties);
        ApplyCatalogDefaults(tableName, normalized);
        normalized = CoercePropertiesForTable(tableName, normalized);
        table.Upsert(transaction, id, normalized);
        _database.GraphLog.AppendNode(tableName, id, normalized);
        UpdateIndexesForNode(tableName, transaction, id, normalized, table);
        _database.MetricsRegistry.AddNodesWritten(1);
    }

    /// <summary>
    /// Upserts a node directly into the in-memory node table and appends to the graph log,
    /// bypassing the Cypher parser. Use this for reliable bulk-write paths where MERGE
    /// Cypher parity is not yet guaranteed.
    /// </summary>
    public void UpsertNodeById(string tableName, string id, Dictionary<string, object> properties)
    {
        ExecuteDirectWrite(() =>
        {
            if (!_database.NodeTables.TryGetValue(tableName, out var table))
            {
                table = new NodeTableData();
                _database.BindTablePersistenceSurface(tableName, table);
                _database.NodeTables[tableName] = table;
            }
            var normalized = NormalizeProperties(tableName, properties);
            ApplyCatalogDefaults(tableName, normalized);
            normalized = CoercePropertiesForTable(tableName, normalized);
            table.Upsert(GetRequiredWriteTransaction(), id, normalized);
            _database.GraphLog.AppendNode(tableName, id, normalized);
            UpdateIndexesForNode(tableName, GetRequiredWriteTransaction(), id, normalized, table);
            _database.MetricsRegistry.AddNodesWritten(1);
        });
    }

    public void UpsertRelationship(string relationshipTableName, object fromNodeId, object toNodeId, Dictionary<string, object> properties)
    {
        var transaction = GetRequiredWriteTransaction();

        if (!_database.RelTables.TryGetValue(relationshipTableName, out var table))
        {
            table = new RelTableData();
            _database.BindTablePersistenceSurface(relationshipTableName, table);
            _database.RelTables[relationshipTableName] = table;
        }

        var key = new EdgeKey(fromNodeId, toNodeId);
        var normalized = NormalizeProperties(relationshipTableName, properties);
        ApplyCatalogDefaults(relationshipTableName, normalized);
        normalized = CoercePropertiesForTable(relationshipTableName, normalized);
        table.Upsert(transaction, key, normalized);
        _database.GraphLog.AppendRel(relationshipTableName, fromNodeId, toNodeId, normalized);
        _database.MetricsRegistry.AddRelationshipsWritten(1);
    }

    /// <summary>
    /// Upserts a relationship directly into the in-memory rel table and appends to the graph log,
    /// bypassing the Cypher parser. Use this for reliable bulk-write paths where MERGE
    /// Cypher parity is not yet guaranteed.
    /// </summary>
    public void UpsertRelationshipById(
        string tableName,
        string fromId,
        string toId,
        Dictionary<string, object> properties)
    {
        ExecuteDirectWrite(() =>
        {
            if (!_database.RelTables.TryGetValue(tableName, out var table))
            {
                table = new RelTableData();
                _database.BindTablePersistenceSurface(tableName, table);
                _database.RelTables[tableName] = table;
            }
            var key = new EdgeKey(fromId, toId);
            var normalized = NormalizeProperties(tableName, properties);
            ApplyCatalogDefaults(tableName, normalized);
            normalized = CoercePropertiesForTable(tableName, normalized);
            table.Upsert(GetRequiredWriteTransaction(), key, normalized);
            _database.GraphLog.AppendRel(tableName, fromId, toId, normalized);
            _database.MetricsRegistry.AddRelationshipsWritten(1);
        });
    }

    private static Dictionary<string, object> NormalizeProperties(string tableName, Dictionary<string, object> properties)
    {
        var normalized = new Dictionary<string, object>(properties.Count, StringComparer.OrdinalIgnoreCase);
        foreach (var (key, value) in properties)
        {
            normalized[key] = TypeCoercionHelper.Normalize(value) ?? string.Empty;
        }
        return normalized;
    }

    private Dictionary<string, object> CoercePropertiesForTable(string tableName, Dictionary<string, object> properties)
    {
        var entry = _database.Catalog.GetTableCatalogEntry(GetCurrentTransactionOrNull(), tableName, useInternal: false);
        return Catalog.PropertyValueCoercion.CoerceProperties(entry, properties);
    }

    private void ApplyCatalogDefaults(string tableName, Dictionary<string, object> properties)
    {
        var entry = _database.Catalog.GetTableCatalogEntry(GetCurrentTransactionOrNull(), tableName, useInternal: false);
        if (entry == null)
            return;

        foreach (var property in entry.GetProperties())
        {
            if (properties.ContainsKey(property.Name) || string.IsNullOrWhiteSpace(property.DefaultExpressionName))
                continue;

            if (TryParseDefaultLiteral(property.DefaultExpressionName, out var defaultValue))
                properties[property.Name] = defaultValue!;
        }
    }

    private static bool TryParseDefaultLiteral(string raw, out object? value)
    {
        value = null;
        if (string.IsNullOrWhiteSpace(raw))
            return false;

        var trimmed = raw.Trim();
        if (string.Equals(trimmed, "null", StringComparison.OrdinalIgnoreCase))
            return true;
        if (string.Equals(trimmed, "true", StringComparison.OrdinalIgnoreCase))
        {
            value = true;
            return true;
        }
        if (string.Equals(trimmed, "false", StringComparison.OrdinalIgnoreCase))
        {
            value = false;
            return true;
        }
        if ((trimmed.StartsWith("'") && trimmed.EndsWith("'")) || (trimmed.StartsWith("\"") && trimmed.EndsWith("\"")))
        {
            value = trimmed[1..^1]
                .Replace("\\'", "'")
                .Replace("\\\"", "\"")
                .Replace("\\\\", "\\")
                .Replace("\\n", "\n")
                .Replace("\\t", "\t")
                .Replace("\\r", "\r");
            return true;
        }
        if (long.TryParse(trimmed, out var longValue))
        {
            value = longValue;
            return true;
        }
        if (double.TryParse(trimmed, System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture, out var doubleValue))
        {
            value = doubleValue;
            return true;
        }

        return false;
    }

    private void UpdateIndexesForNode(string tableName, BogDb.Core.Transaction.Transaction tx, object id, Dictionary<string, object> props, NodeTableData table)
        => _database.UpdateNodeIndexes(tableName, tx, id, props, table);

    private string FormatValue(object value)
    {
        return value switch
        {
            string s => $"'{s}'",
            DateTime d => $"date('{d:yyyy-MM-dd}')",
            bool b => b ? "true" : "false",
            _ => value.ToString() ?? "null"
        };
    }
    
    public Dictionary<string, object>? ReadNode(string tableName, object id)
    {
        var tx = _activeTransaction ?? ClientContext.ActiveTransaction;
        if (_database.NodeTables.TryGetValue(tableName, out var table))
        {
            Dictionary<string, object>? props;
            var found = tx is null
                ? table.TryGetProperties(id, out props)
                : table.TryGetProperties(tx, id, out props);
            if (found)
            {
                _database.MetricsRegistry.AddNodeReads(1);
                return NormalizeReadProperties(tableName, props);
            }
        }
        return null;
    }

    /// <summary>
    /// Returns the names of all node tables currently registered in the database.
    /// </summary>
    public IReadOnlyList<string> GetNodeTableNames()
        => new List<string>(_database.NodeTables.Keys);

    /// <summary>
    /// Returns the properties of a node identified by <paramref name="id"/> by
    /// searching all node tables. Returns null if not found.
    /// </summary>
    public Dictionary<string, object>? GetNodeById(string id, out string? tableName)
    {
        var tx = _activeTransaction ?? ClientContext.ActiveTransaction;
        foreach (var (name, table) in _database.NodeTables)
        {
            Dictionary<string, object>? props;
            var found = tx is null
                ? table.TryGetProperties(id, out props)
                : table.TryGetProperties(tx, id, out props);
            if (found)
            {
                _database.MetricsRegistry.AddNodeReads(1);
                tableName = name;
                return NormalizeReadProperties(name, props);
            }
        }
        tableName = null;
        return null;
    }

    /// <summary>
    /// Returns all outgoing edges from <paramref name="fromId"/>.  
    /// Each result tuple is (tableName, toId, properties).
    /// Optionally filtered by relationship table name.
    /// </summary>
    public IReadOnlyList<(string TableName, string FromId, string ToId, Dictionary<string, object> Properties)>
        GetOutgoingEdges(string fromId, string? label = null)
    {
        var tx = _activeTransaction ?? ClientContext.ActiveTransaction;
        var results = new List<(string, string, string, Dictionary<string, object>)>();
        foreach (var (tableName, tableData) in _database.RelTables)
        {
            if (label is not null && !string.Equals(tableName, label, StringComparison.Ordinal))
                continue;

            var rows = tx is null
                ? tableData.EnumerateRows()
                : tableData.EnumerateRows(tx);
            foreach (var (key, props) in rows)
            {
                var from = key.From?.ToString();
                if (!string.Equals(from, fromId, StringComparison.Ordinal))
                    continue;

                var to = key.To?.ToString() ?? string.Empty;
                results.Add((tableName, fromId, to, NormalizeReadProperties(tableName, props)));
            }
        }
        _database.MetricsRegistry.AddRelReads(results.Count);
        return results;
    }

    /// <summary>
    /// Returns all incoming edges to <paramref name="toId"/>.
    /// Each result tuple is (tableName, fromId, toId, properties).
    /// Optionally filtered by relationship table name.
    /// </summary>
    public IReadOnlyList<(string TableName, string FromId, string ToId, Dictionary<string, object> Properties)>
        GetIncomingEdges(string toId, string? label = null)
    {
        var tx = _activeTransaction ?? ClientContext.ActiveTransaction;
        var results = new List<(string, string, string, Dictionary<string, object>)>();
        foreach (var (tableName, tableData) in _database.RelTables)
        {
            if (label is not null && !string.Equals(tableName, label, StringComparison.Ordinal))
                continue;

            var rows = tx is null
                ? tableData.EnumerateRows()
                : tableData.EnumerateRows(tx);
            foreach (var (key, props) in rows)
            {
                var to = key.To?.ToString();
                if (!string.Equals(to, toId, StringComparison.Ordinal))
                    continue;

                var from = key.From?.ToString() ?? string.Empty;
                results.Add((tableName, from, toId, NormalizeReadProperties(tableName, props)));
            }
        }
        _database.MetricsRegistry.AddRelReads(results.Count);
        return results;
    }

    private Dictionary<string, object> NormalizeReadProperties(
        string tableName,
        Dictionary<string, object>? props)
    {
        if (props is null)
            return new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase);

        var entry = _database.Catalog.GetTableCatalogEntry(GetCurrentTransactionOrNull(), tableName, useInternal: false);
        return Catalog.PropertyValueCoercion.CoerceProperties(entry, props);
    }

    private bool IsRegisteredFileSystemPath(string filePath)
    {
        var schemeSeparator = filePath.IndexOf("://", StringComparison.Ordinal);
        if (schemeSeparator <= 0)
            return false;

        var scheme = filePath[..schemeSeparator];
        return _database.TryGetFileSystem(scheme, out _);
    }

    private string ReadAllTextFromPath(string filePath)
    {
        if (TryReadAllTextFromRegisteredFileSystem(filePath, out var content))
            return content;

        if (!System.IO.File.Exists(filePath))
            throw new System.IO.FileNotFoundException("Cypher script not found.", filePath);

        return System.IO.File.ReadAllText(filePath);
    }

    private bool TryReadAllTextFromRegisteredFileSystem(string filePath, out string content)
    {
        content = string.Empty;
        var schemeSeparator = filePath.IndexOf("://", StringComparison.Ordinal);
        if (schemeSeparator <= 0)
            return false;

        var scheme = filePath[..schemeSeparator];
        if (!_database.TryGetFileSystem(scheme, out var fileSystem))
            return false;

        using var fileInfo = fileSystem.OpenFile(filePath, FileFlags.Read);
        var fileSize = checked((int)fileInfo.GetFileSize());
        var buffer = new byte[fileSize];
        fileInfo.Read(buffer, 0);
        content = System.Text.Encoding.UTF8.GetString(buffer);
        return true;
    }

    public void Dispose()
    {
        // Roll back any transaction still open at dispose time. Without this, disposing a connection with
        // an uncommitted write transaction — e.g. an exception escaping a `using` block — leaves the
        // transaction registered forever: the single-writer slot is never released and every later write on
        // any connection fails "Only one write transaction". SqlConnection/SQLite roll back on dispose the
        // same way. Best-effort — Dispose must not throw.
        if ((_activeTransaction ?? ClientContext.ActiveTransaction) != null)
        {
            try { Rollback(); }
            catch { /* releasing the slot is best-effort; Dispose cannot propagate an exception */ }
        }

        _activeTransaction = null;
        ClientContext.Dispose();
    }

    internal Transaction.Transaction? GetCurrentTransactionOrNull()
        => _activeTransaction ?? ClientContext.ActiveTransaction;

    private void ExecuteDirectWrite(Action action)
    {
        ExecuteWriteTransaction(action);
    }

    private void StartTransaction(BogDb.Core.Transaction.TransactionType type)
    {
        if (type == BogDb.Core.Transaction.TransactionType.WRITE)
        {
            EnsureDatabaseWritable();
        }

        ClientContext.StartTransaction(type);
        var transaction = ClientContext.ActiveTransaction;
        if (transaction != null && transaction.IsWriteTransaction())
        {
            transaction.CaptureRecoveryOffsets(
                _database.StorageManager.GetWAL().GetFileSize(),
                _database.GraphLog.GetFileSize());
        }
    }

    private Transaction.Transaction GetRequiredWriteTransaction()
    {
        if (_database.IsReadOnly)
            throw new InvalidOperationException("Database is open in read-only mode.");

        var transaction = GetCurrentTransactionOrNull();
        if (transaction == null || !transaction.IsWriteTransaction())
            throw new InvalidOperationException("Requires write transaction.");
        return transaction;
    }

    private void EnsureDatabaseWritable()
    {
        if (_database.IsReadOnly)
            throw new InvalidOperationException("Database is open in read-only mode.");
    }

    private sealed class QuerySyntaxErrorListener(List<string> errors) : BaseErrorListener
    {
        public override void SyntaxError(
            TextWriter output,
            IRecognizer recognizer,
            IToken offendingSymbol,
            int line,
            int charPositionInLine,
            string msg,
            RecognitionException e)
        {
            errors.Add($"Syntax error at line {line}, column {charPositionInLine}: {msg}");
        }
    }

    private sealed class QueryLexerSyntaxErrorListener(List<string> errors) : IAntlrErrorListener<int>
    {
        public void SyntaxError(
            TextWriter output,
            IRecognizer recognizer,
            int offendingSymbol,
            int line,
            int charPositionInLine,
            string msg,
            RecognitionException e)
        {
            errors.Add($"Syntax error at line {line}, column {charPositionInLine}: {msg}");
        }
    }

    private readonly record struct PreparedStatementMetadata(
        IReadOnlyList<BogDbColumnDescriptor> ResultColumns,
        IReadOnlyDictionary<string, BogDbLogicalType> ParameterExpectedTypes);
}
